import React, { createContext, useContext, useReducer, useEffect } from 'react';
import { authService } from '../services/api';
import socketService from '../services/socket';

const AuthContext = createContext();

// Estados del usuario
const initialState = {
    user: null,
    isAuthenticated: false,
    isLoading: true,
    error: null
};

// Reducer para manejar estados
const authReducer = (state, action) => {
    switch (action.type) {
        case 'LOGIN_SUCCESS':
            return {
                ...state,
                user: action.payload,
                isAuthenticated: true,
                isLoading: false,
                error: null
            };
        case 'LOGIN_FAILURE':
            return {
                ...state,
                user: null,
                isAuthenticated: false,
                isLoading: false,
                error: action.payload
            };
        case 'LOGOUT':
            return {
                ...state,
                user: null,
                isAuthenticated: false,
                isLoading: false,
                error: null
            };
        case 'SET_LOADING':
            return {
                ...state,
                isLoading: action.payload
            };
        case 'CLEAR_ERROR':
            return {
                ...state,
                error: null
            };
        case 'SET_USER':
            return {
                ...state,
                user: action.payload,
                isAuthenticated: true,
                isLoading: false
            };
        default:
            return state;
    }
};

export const AuthProvider = ({ children }) => {
    const [state, dispatch] = useReducer(authReducer, initialState);

    // Verificar si hay una sesión activa al cargar la app
    useEffect(() => {
        const checkAuthStatus = async () => {
            try {
                const user = authService.getCurrentUser();
                const isAuthenticated = authService.isAuthenticated();

                if (isAuthenticated && user) {
                    dispatch({ type: 'SET_USER', payload: user });
                    
                    // Conectar socket con el token actual (opcional - comentado por ahora)
                    // const token = localStorage.getItem('accessToken');
                    // if (token) {
                    //     socketService.connect(token);
                    //     socketService.joinRole(user.rol);
                    // }
                } else {
                    dispatch({ type: 'SET_LOADING', payload: false });
                }
            } catch (error) {
                console.error('Error verificando autenticación:', error);
                dispatch({ type: 'SET_LOADING', payload: false });
            }
        };

        checkAuthStatus();
    }, []);

    // Función de login
    const login = async (email, password) => {
        try {
            dispatch({ type: 'SET_LOADING', payload: true });
            dispatch({ type: 'CLEAR_ERROR' });

            const response = await authService.login(email, password);
            const { usuario } = response;

            dispatch({ type: 'LOGIN_SUCCESS', payload: usuario });

            // Conectar socket (comentado por ahora para evitar errores)
            // const { accessToken } = response;
            // socketService.connect(accessToken);
            // socketService.joinRole(usuario.rol);

            return { success: true, user: usuario };
        } catch (error) {
            const errorMessage = error.response?.data?.error || 'Error al iniciar sesión';
            dispatch({ type: 'LOGIN_FAILURE', payload: errorMessage });
            return { success: false, error: errorMessage };
        }
    };

    // Función de logout
    const logout = () => {
        authService.logout();
        // socketService.disconnect(); // Comentado por ahora
        dispatch({ type: 'LOGOUT' });
    };

    // Verificar si el usuario tiene un rol específico
    const hasRole = (role) => {
        return state.user && state.user.rol === role;
    };

    // Verificar si el usuario tiene alguno de los roles especificados
    const hasAnyRole = (roles) => {
        return state.user && roles.includes(state.user.rol);
    };

    const value = {
        // Estado
        user: state.user,
        isAuthenticated: state.isAuthenticated,
        isLoading: state.isLoading,
        error: state.error,
        
        // Funciones
        login,
        logout,
        hasRole,
        hasAnyRole,
        clearError: () => dispatch({ type: 'CLEAR_ERROR' })
    };

    return (
        <AuthContext.Provider value={value}>
            {children}
        </AuthContext.Provider>
    );
};

// Hook personalizado para usar el contexto
export const useAuth = () => {
    const context = useContext(AuthContext);
    if (!context) {
        throw new Error('useAuth debe ser usado dentro de un AuthProvider');
    }
    return context;
};

export default AuthContext;
